function solve(prices, strategy, k) {
    const n = prices.length;
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    let maxProfit = originalProfit;
    const halfK = k / 2;

    // Precompute the prefix sums of the original strategy's contribution
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + strategy[i] * prices[i];
    }

    // Precompute the sum of the modified strategy's contribution for the window
    // The modified strategy is 0 for first half and 1 for second half
    for (let i = 0; i <= n - k; i++) {
        const start = i;
        const end = i + k;
        let modifiedSum = 0;

        // First half (set to 0)
        const firstHalfEnd = start + halfK;
        // Contribution is 0 * prices[part] = 0

        // Second half (set to 1)
        const secondHalfStart = firstHalfEnd;
        const secondHalfEnd = end;
        for (let j = secondHalfStart; j < secondHalfEnd; j++) {
            modifiedSum += prices[j];
        }

        // Original sum for the window
        const originalWindowSum = prefix[end] - prefix[start];

        // New profit is originalProfit - originalWindowSum + modifiedSum
        const newProfit = originalProfit - originalWindowSum + modifiedSum;
        if (newProfit > maxProfit) {
            maxProfit = newProfit;
        }
    }

    return maxProfit;
}

